'use client'

import { useState } from 'react';

interface CheckoutFormProps {
  eventoId: string;
  eventoSlug: string;
  theme?: any;
}

export default function CheckoutForm({ eventoId, eventoSlug, theme }: CheckoutFormProps) {
  const [step, setStep] = useState(1);
  const [loading, setLoading] = useState(false);
  const [email, setEmail] = useState('');
  const [nombre, setNombre] = useState('');
  const [otpCode, setOtpCode] = useState('');
  const [otpToken, setOtpToken] = useState('');
  const [statusText, setStatusText] = useState('CONTINUAR');
  const [errorMsg, setErrorMsg] = useState('');

  const primaryColor = theme?.primaryColor || '#ffffff';
  const secondaryColor = theme?.secondaryColor || '#888888';
  const textColor = theme?.textColor || 'text-white';
  const buttonClass = `w-full py-4 mt-4 font-semibold tracking-wide text-lg rounded-xl transition-colors disabled:opacity-50`;

  const validateEmail = (email: string) => {
    return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);
  };

  const handleRequestCode = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!email || !nombre) {
      setErrorMsg("Completa todos los campos.");
      return;
    }
    setErrorMsg('');
    setLoading(true);
    setStatusText('ENVIANDO C├ôDIGO...');

    if (!validateEmail(email)) {
      setErrorMsg("El formato del email es inv├ílido.");
      setLoading(false);
      setStatusText('CONTINUAR');
      return;
    }

    try {
      const response = await fetch('/api/send-code', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ email, eventoId })
      });

      const data = await response.json();

      if (!response.ok) {
        setErrorMsg(data.error || "Hubo un error con tu solicitud.");
        setLoading(false);
        setStatusText('CONTINUAR');
        return;
      }

      const { token } = data;
      setOtpToken(token);
      setStep(2);
      setStatusText('VALIDAR C├ôDIGO');
      setLoading(false);
    } catch (error) {
      console.error(error);
      setErrorMsg("Error enviando c├│digo.");
      setLoading(false);
      setStatusText('CONTINUAR');
    }
  };

  const handleVerifyAndCheckout = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!otpCode || otpCode.length !== 6) {
      setErrorMsg("Ingresa un c├│digo v├ílido de 6 d├¡gitos.");
      return;
    }
    setErrorMsg('');
    setLoading(true);
    setStatusText('VALIDANDO...');

    try {
      const response = await fetch('/api/checkout', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ nombre, email, token: otpToken, code: otpCode, eventoId })
      });

      const data = await response.json();

      if (!response.ok) {
        setErrorMsg(data.error || "C├│digo incorrecto.");
        setLoading(false);
        setStatusText('VALIDAR C├ôDIGO');
        return;
      }

      if (data.url) {
        window.location.href = data.url;
      } else {
        setErrorMsg("Error contactando a Mercado Pago.");
        setLoading(false);
        setStatusText('VALIDAR C├ôDIGO');
      }
    } catch (error) {
      console.error(error);
      setErrorMsg("Error procesando validaci├│n.");
      setLoading(false);
      setStatusText('VALIDAR C├ôDIGO');
    }
  };

  return (
    <>
      {step === 1 ? (
        <form onSubmit={handleRequestCode} className="space-y-4 pt-6 w-full">
          <input
            type="text"
            required
            placeholder="Tu nombre completo"
            className="w-full px-4 py-3 bg-neutral-950 text-white rounded-xl border border-neutral-800 focus:outline-none focus:ring-1 focus:ring-neutral-500 transition-all font-light placeholder:text-neutral-600"
            value={nombre}
            onChange={(e) => setNombre(e.target.value)}
          />
          <input
            type="email"
            required
            placeholder="Introduce tu e-mail"
            className="w-full px-4 py-3 bg-neutral-950 text-white rounded-xl border border-neutral-800 focus:outline-none focus:ring-1 transition-all font-light placeholder:text-neutral-600"
            value={email}
            onChange={(e) => setEmail(e.target.value)}
          />
          {errorMsg && (
            <p className="text-red-500 text-sm font-medium animate-fade-in text-center">{errorMsg}</p>
          )}
          <button
            type="submit"
            disabled={loading}
            className={buttonClass}
            style={{ backgroundColor: primaryColor, color: theme?.backgroundColor || 'black' }}
          >
            {statusText}
          </button>
        </form>
      ) : (
        <form onSubmit={handleVerifyAndCheckout} className="space-y-4 pt-6 animate-fade-in w-full">
          <h2 className="text-2xl font-bold mb-2">Valida tu Email</h2>
          <p className="text-neutral-400 text-sm mb-6">Hemos enviado un c├│digo de 6 d├¡gitos a <br/><span className="text-white font-medium">{email}</span></p>
          <input
            type="text"
            required
            placeholder="C├│digo de 6 d├¡gitos"
            maxLength={6}
            className="w-full px-4 py-3 bg-neutral-950 text-white rounded-xl border border-neutral-800 focus:outline-none focus:ring-1 transition-all font-monospace text-center tracking-[0.5em] text-2xl placeholder:text-neutral-600 placeholder:tracking-normal placeholder:text-base"
            value={otpCode}
            onChange={(e) => setOtpCode(e.target.value.replace(/\D/g, ''))}
          />
          {errorMsg && (
            <p className="text-red-500 text-sm font-medium animate-fade-in text-center">{errorMsg}</p>
          )}
          <button
            type="submit"
            disabled={loading || otpCode.length !== 6}
            className={buttonClass}
            style={{ backgroundColor: primaryColor, color: theme?.backgroundColor || 'black' }}
          >
            {statusText}
          </button>
          <button
            type="button"
            disabled={loading}
            onClick={() => { setStep(1); setErrorMsg(''); setStatusText('CONTINUAR'); }}
            className="w-full py-2 mt-2 bg-transparent text-neutral-500 text-sm hover:text-white transition-colors disabled:opacity-50"
          >
            Volver atr├ís
          </button>
        </form>
      )}
    </>
  );
}

'use client'

import { useState } from 'react'
import { createClient } from '@/utils/supabase/client'
import { UploadCloud, Loader2, Image as ImageIcon, Video } from 'lucide-react'

interface FileUploaderProps {
  bucket: string
  folder?: string
  accept?: string
  maxSizeMB?: number
  onUploadSuccess: (url: string) => void
  currentUrl?: string
}

export default function FileUploader({ 
  bucket, 
  folder = '', 
  accept = 'image/*', 
  maxSizeMB = 10,
  onUploadSuccess,
  currentUrl
}: FileUploaderProps) {
  const [isUploading, setIsUploading] = useState(false)
  const [error, setError] = useState<string | null>(null)
  const supabase = createClient()

  const handleUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0]
    if (!file) return

    setError(null)

    if (file.size > maxSizeMB * 1024 * 1024) {
      setError(`El archivo supera el tama├▒o m├íximo permitido de ${maxSizeMB}MB`)
      return
    }

    try {
      setIsUploading(true)
      const fileExt = file.name.split('.').pop()
      const fileName = `${Math.random().toString(36).substring(2, 15)}_${Date.now()}.${fileExt}`
      const filePath = folder ? `${folder}/${fileName}` : fileName

      const { data, error: uploadError } = await supabase.storage
        .from(bucket)
        .upload(filePath, file, { upsert: true })

      if (uploadError) throw uploadError

      const { data: publicUrlData } = supabase.storage
        .from(bucket)
        .getPublicUrl(data.path)

      onUploadSuccess(publicUrlData.publicUrl)
    } catch (err: any) {
      console.error(err)
      setError(err.message || 'Ocurri├│ un error al subir el archivo.')
    } finally {
      setIsUploading(false)
    }
  }

  const isVideo = currentUrl?.match(/\.(mp4|webm|ogg)$/i) || accept.includes('video')

  return (
    <div className="space-y-4">
      {currentUrl ? (
        <div className="relative rounded-xl overflow-hidden border border-neutral-800 bg-neutral-900 aspect-video flex items-center justify-center">
          {isVideo ? (
            <video src={currentUrl} controls className="w-full h-full object-cover" />
          ) : (
            <img src={currentUrl} alt="Preview" className="w-full h-full object-cover" />
          )}
          <div className="absolute inset-0 bg-black/50 opacity-0 hover:opacity-100 transition-opacity flex items-center justify-center">
            <label className="cursor-pointer px-4 py-2 bg-white text-black font-semibold rounded-lg hover:bg-neutral-200 transition-colors">
              Cambiar Archivo
              <input type="file" accept={accept} className="hidden" onChange={handleUpload} disabled={isUploading} />
            </label>
          </div>
        </div>
      ) : (
        <label className={`flex flex-col items-center justify-center w-full h-32 border-2 border-dashed rounded-xl cursor-pointer transition-colors ${
          error ? 'border-red-500/50 bg-red-900/10' : 'border-neutral-800 hover:border-neutral-600 bg-neutral-900/50 hover:bg-neutral-900'
        }`}>
          <div className="flex flex-col items-center justify-center pt-5 pb-6">
            {isUploading ? (
              <Loader2 className="w-8 h-8 text-neutral-400 animate-spin mb-2" />
            ) : isVideo ? (
              <Video className="w-8 h-8 text-neutral-400 mb-2" />
            ) : (
              <UploadCloud className="w-8 h-8 text-neutral-400 mb-2" />
            )}
            <p className="text-sm text-neutral-400">
              {isUploading ? 'Subiendo...' : 'Click para seleccionar archivo'}
            </p>
            <p className="text-xs text-neutral-500 mt-1">M├íx {maxSizeMB}MB</p>
          </div>
          <input type="file" accept={accept} className="hidden" onChange={handleUpload} disabled={isUploading} />
        </label>
      )}
      {error && <p className="text-sm text-red-500">{error}</p>}
    </div>
  )
}

import React from 'react'

// Common props for all sections
export interface SectionProps {
  evento: any
  artistas?: any[]
  productora?: any
  seccion: any // contains contenido_json and other data
}

// Simple fallback components if a theme doesn't implement a section
